def controls_for_framework(library: list[EnterpriseControl],
                            framework: Framework) -> list[tuple[EnterpriseControl, list[FrameworkCitation]]]:
    """Return all controls that cite a given framework, with their citations."""
    results = []
    for ctrl in library:
        citations = ctrl.satisfies(framework)
        if citations:
            results.append((ctrl, citations))
    return results


def compliance_coverage(library: list[EnterpriseControl]) -> dict[str, int]:
    """Count how many controls cite each framework."""
    coverage: dict[str, int] = {}
    for ctrl in library:
        for framework in ctrl.framework_ids():
            coverage[framework] = coverage.get(framework, 0) + 1
    return coverage


